#include <iostream>
#include <string>
#include <vector>

// --- Template Functions ---

// Generic function that works with any type
template <typename T>
T maxValue(T a, T b) {
    return (a > b) ? a : b;
}

template <typename T>
void swapValues(T& a, T& b) {
    T temp = a;
    a = b;
    b = temp;
}

// --- Template Class ---

template <typename T>
class Box {
private:
    T value;

public:
    Box(T v) : value(v) {}

    T getValue() const { return value; }
    void setValue(T v) { value = v; }

    void display() const {
        std::cout << "Box contains: " << value << std::endl;
    }
};

// --- Template Class with multiple types ---

template <typename T1, typename T2>
class Pair {
private:
    T1 first;
    T2 second;

public:
    Pair(T1 f, T2 s) : first(f), second(s) {}

    T1 getFirst() const { return first; }
    T2 getSecond() const { return second; }

    void display() const {
        std::cout << "First: " << first << ", Second: " << second << std::endl;
    }
};

// --- Template with specialization ---

template <typename T>
class Storage {
public:
    void store(T value) {
        std::cout << "Storing generic value: " << value << std::endl;
    }
};

// Specialization for bool
template <>
class Storage<bool> {
public:
    void store(bool value) {
        std::cout << "Storing boolean: " << (value ? "true" : "false") << std::endl;
    }
};

// --- Game use: generic stats container ---

template <typename T>
class GameStat {
private:
    std::string name;
    T value;
    T maxValue;

public:
    GameStat(std::string n, T v, T max) : name(n), value(v), maxValue(max) {}

    void add(T amount) {
        value += amount;
        if (value > maxValue) value = maxValue;
    }

    void subtract(T amount) {
        value -= amount;
        if (value < 0) value = 0;
    }

    void display() const {
        std::cout << name << ": " << value << "/" << maxValue << std::endl;
    }

    T getValue() const { return value; }
};

int main() {
    std::cout << "=== Templates — Generic Game Components ===" << std::endl;

    // 1. Template functions
    std::cout << "\n--- Template Functions ---" << std::endl;
    std::cout << "maxValue(5, 10): " << maxValue(5, 10) << std::endl;
    std::cout << "maxValue(3.14, 2.71): " << maxValue(3.14, 2.71) << std::endl;
    std::cout << "maxValue('a', 'z'): " << maxValue('a', 'z') << std::endl;

    int a = 5, b = 10;
    swapValues(a, b);
    std::cout << "After swap: a=" << a << ", b=" << b << std::endl;

    // 2. Template class
    std::cout << "\n--- Template Class ---" << std::endl;
    Box<int> intBox(42);
    intBox.display();

    Box<std::string> stringBox("Hello, Templates!");
    stringBox.display();

    Box<double> doubleBox(3.14159);
    doubleBox.display();

    // 3. Multiple template parameters
    std::cout << "\n--- Multiple Parameters ---" << std::endl;
    Pair<int, std::string> pair1(1, "First");
    pair1.display();

    Pair<std::string, double> pair2("Pi", 3.14159);
    pair2.display();

    // 4. Template specialization
    std::cout << "\n--- Template Specialization ---" << std::endl;
    Storage<int> intStorage;
    intStorage.store(42);

    Storage<bool> boolStorage;
    boolStorage.store(true);
    boolStorage.store(false);

    // 5. Game use: generic stats
    std::cout << "\n--- Game Stats (Generic) ---" << std::endl;
    GameStat<int> health("Health", 100, 150);
    GameStat<double> mana("Mana", 50.0, 100.0);
    GameStat<int> stamina("Stamina", 80, 100);

    health.display();
    mana.display();
    stamina.display();

    health.add(30);
    mana.subtract(25.5);
    stamina.subtract(50);

    std::cout << "\nAfter updates:" << std::endl;
    health.display();
    mana.display();
    stamina.display();

    std::cout << "\n--- Why Use Templates? ---" << std::endl;
    std::cout << "✅ Write once, use with any type" << std::endl;
    std::cout << "✅ Type-safe at compile time" << std::endl;
    std::cout << "✅ No runtime overhead" << std::endl;
    std::cout << "✅ Used by STL containers" << std::endl;

    return 0;
}

