#include <iostream>
#include <string>

template <typename T>
bool isEqual(T a, T b) {
    return a == b;
}

template <typename T>
class Container {
private:
    T value;

public:
    Container(T v) : value(v) {}

    T getValue() const { return value; }
    void setValue(T v) { value = v; }

    void display() const {
        std::cout << "Container: " << value << std::endl;
    }
};

int main() {
    std::cout << "=== Template Function ===" << std::endl;
    std::cout << "isEqual(5, 5): " << isEqual(5, 5) << std::endl;
    std::cout << "isEqual(5, 3): " << isEqual(5, 3) << std::endl;
    std::cout << "isEqual(3.14, 3.14): " << isEqual(3.14, 3.14) << std::endl;
    std::cout << "isEqual(\"Hello\", \"Hello\"): " << isEqual(std::string("Hello"), std::string("Hello")) << std::endl;

    std::cout << "\n=== Template Class ===" << std::endl;
    Container<int> intContainer(42);
    intContainer.display();

    Container<std::string> stringContainer("Hello");
    stringContainer.display();

    Container<double> doubleContainer(3.14);
    doubleContainer.display();

    return 0;
}
